Sure, I can provide you with a basic Snake game using HTML, CSS, and JavaScript.

HTML CODE:

```
<!DOCTYPE html>
<html>
<head>
	<title>Snake Game</title>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<link rel="stylesheet" type="text/css" href="style.css">
</head>
<body>
	<div class="container">
		<div class="game-area"></div>
		<div class="score-box">Score: <span id="score">0</span></div>
		<button id="start-btn">Start</button>
	</div>

	<script src="script.js"></script>
</body>
</html>
```

CSS CODE:

```
* {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}

body {
	font-family: Arial, Helvetica, sans-serif;
	background-color: #333;
	color: #fff;
}

.container {
	max-width: 600px;
	margin: 0 auto;
}

.game-area {
	width: 600px;
	height: 400px;
	background-color: #ccc;
	position: relative;
	margin-bottom: 10px;
}

.score-box {
	font-size: 24px;
	margin-bottom: 10px;
}

#start-btn {
	font-size: 18px;
	padding: 10px 20px;
	background-color: #fff;
	border: none;
	color: #333;
	cursor: pointer;
}
```

JAVASCRIPT CODE:

```
var gameArea = document.querySelector(".game-area");
var scoreDisplay = document.querySelector("#score");
var startBtn = document.querySelector("#start-btn");

var snakeSize = 20;
var width = gameArea.offsetWidth;
var height = gameArea.offsetHeight;
var score = 0;
var snake = [];

function createSnake() {
	snake.push({ x: 10 * snakeSize, y: height / 2 });
	snake.push({ x: 9 * snakeSize, y: height / 2 });
	snake.push({ x: 8 * snakeSize, y: height / 2 });
}

function drawSnake() {
	for (var i = 0; i < snake.length; i++) {
		var snakeBlock = document.createElement("span");
		snakeBlock.style.width = snakeSize + "px";
		snakeBlock.style.height = snakeSize + "px";
		snakeBlock.style.backgroundColor = "green";
		snakeBlock.style.position = "absolute";
		snakeBlock.style.left = snake[i].x + "px";
		snakeBlock.style.top = snake[i].y + "px";
		gameArea.appendChild(snakeBlock);
	}
}

function moveSnake() {
	snake.pop();
	var headX = snake[0].x;
	var headY = snake[0].y;

	if (direction == "right") {
		headX += snakeSize;
	} else if (direction == "left") {
		headX -= snakeSize;
	} else if (direction == "down") {
		headY += snakeSize;
	} else if (direction == "up") {
		headY -= snakeSize;
	}

	var newHead = { x: headX, y: headY };
	snake.unshift(newHead);
}

function deleteSnake() {
	var snakeBlocks = document.querySelectorAll(".game-area span");
	for (var i = 0; i < snakeBlocks.length; i++) {
		snakeBlocks[i].parentNode.removeChild(snakeBlocks[i]);
	}
}

function generateFood() {
	var foodX = Math.floor(Math.random() * width / snakeSize) * snakeSize;
	var foodY = Math.floor(Math.random() * height / snakeSize) * snakeSize;

	var food = document.createElement("span");
	food.style.width = snakeSize + "px";
	food.style.height = snakeSize + "px";
	food.style.backgroundColor = "red";
	food.style.position = "absolute";
	food.style.left = foodX + "px";
	food.style.top = foodY + "px";
	gameArea.appendChild(food);
	return { x: foodX, y: foodY };
}

function checkCollision() {
	var headX = snake[0].x;
	var headY = snake[0].y;

	if (headX < 0 || headX >= width || headY < 0 || headY >= height) {
		return true;
	}

	for (var i = 1; i < snake.length; i++) {
		if (headX == snake[i].x && headY == snake[i].y) {
			return true;
		}
	}

	return false;
}

function checkFood() {
	var headX = snake[0].x;
	var headY = snake[0].y;
	var foodX = food.x;
	var foodY = food.y;

	if (headX == foodX && headY == foodY) {
		score++;
		scoreDisplay.innerHTML = score;
		snake.push(snake[snake.length - 1]);
		deleteSnake();
		drawSnake();
		food = generateFood();
	}
}

var direction;

document.addEventListener("keydown", function(event) {
	if (event.keyCode == 37 && direction != "right") {
		direction = "left";
	} else if (event.keyCode == 38 && direction != "down") {
		direction = "up";
	} else if (event.keyCode == 39 && direction != "left") {
		direction = "right";
	} else if (event.keyCode == 40 && direction != "up") {
		direction = "down";
	}
});

startBtn.addEventListener("click", function() {
	score = 0;
	direction = "right";
	snake = [];
	deleteSnake();
	createSnake();
	drawSnake();
	food = generateFood();
	scoreDisplay.innerHTML = score;
	startGame();
});

function startGame() {
	setTimeout(function() {
		if (checkCollision()) {
			alert("Game Over");
			return;
		}
		moveSnake();
		checkFood();
		startGame();
	}, 100);
}
```

This code creates a simple Snake game with a score box and a start button. The player controls the snake using the arrow keys and must eat red food blocks to grow in size. If the snake collides with the wall or its own body, the game is over.

Hope this helps!

You are right, using the universal selector `*` in CSS can lead to performance issues and unintended style inheritance. A better approach is to target specific elements or classes.

Here's the updated CSS code:

```
html {
	font-family: Arial, Helvetica, sans-serif;
	background-color: #333;
	color: #fff;
}

.container {
	max-width: 600px;
	margin: 0 auto;
}

.game-area {
	width: 600px;
	height: 400px;
	background-color: #ccc;
	position: relative;
	margin-bottom: 10px;
}

.score-box {
	font-size: 24px;
	margin-bottom: 10px;
}

#start-btn {
	font-size: 18px;
	padding: 10px 20px;
	background-color: #fff;
	border: none;
	color: #333;
	cursor: pointer;
}

span {
	width: 20px;
	height: 20px;
	position: absolute;
}

.snake-block {
	background-color: green;
}

.food-block {
	background-color: red;
}
```

In this code, we removed the universal selector and targeted specific elements and classes instead. We also added more specific class selectors for the snake and food blocks.

Hope this helps!

Sure, here's how you can create a website that displays a picture of Rick Astley when a button is clicked:

HTML CODE:

```
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Rick Astley Website</title>
    <link rel="stylesheet" href="styles.css">
</head>
<body>
    <div class="container">
        <h1>Rick Astley Website</h1>
        <button id="rick-btn">Go</button>
        <div id="rick-container"></div>
    </div>
    <script src="script.js"></script>
</body>
</html>
```

CSS CODE:

```
* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: Arial, sans-serif;
    background-color: #333;
    color: #fff;
}

.container {
    max-width: 600px;
    margin: 0 auto;
    text-align: center;
    padding: 20px;
}

h1 {
    font-size: 40px;
    margin-bottom: 20px;
}

button {
    font-size: 28px;
    padding: 10px 20px;
    border: none;
    background-color: #ff5733;
    color: #fff;
    cursor: pointer;
}

#rick-container {
    display: none;
}

img {
    max-width: 100%;
    height: auto;
}
```

JAVASCRIPT CODE:

```
var rickBtn = document.querySelector("#rick-btn");
var rickContainer = document.querySelector("#rick-container");

rickBtn.addEventListener("click", function() {
    rickContainer.style.display = "block";
});

```

In this code, there is a container with a heading, a button, and a div to hold the Rick Astley picture. The CSS styling is used to style the text, button, and image.

The JavaScript code listens for a click event on the button, and when the button is clicked, changes the style of the Rick Astley image container to display the image.

You can download or save the three files `index.html`, `styles.css`, and `script.js` in the same folder on your computer, and open the `index.html` file in your web browser to see the website in action. When you click the "Go" button, the picture of Rick Astley will appear.

I hope that helps!
